{"path":"/home/user/workspace/lib/api.ts","content":"import type { Comment, Post } from '@/lib/types';

const API_BASE_URL = 'https://jsonplaceholder.typicode.com';

type FetchOptions = RequestInit & {
  next?: NextFetchRequestConfig;
};

async function fetchJson<T>(path: string, options?: FetchOptions): Promise<T | null> {
  const response = await fetch(`${API_BASE_URL}${path}`, options);

  if (!response.ok) {
    if (response.status === 404) {
      return null;
    }

    throw new Error(`Request failed with status ${response.status}`);
  }

  return (await response.json()) as T;
}

export async function fetchPosts(limit?: number, options?: FetchOptions): Promise<Post[]> {
  const search = typeof limit === 'number' ? `?_limit=${limit}` : '';
  const posts = await fetchJson<Post[]>(`/posts${search}`, options);

  return posts ?? [];
}

export async function fetchPostById(id: string): Promise<Post | null> {
  return fetchJson<Post>(`/posts/${id}`, {
    next: { revalidate: 300 },
  });
}

export async function fetchCommentsByPostId(id: string): Promise<Comment[]> {
  const comments = await fetchJson<Comment[]>(`/posts/${id}/comments`, {
    next: { revalidate: 300 },
  });

  return comments ?? [];
}
"}

